.Text = "Blackhole: OFF" BlackholeBtn.TextColor3 = Color3.fromRGB(255, 255, 255) BlackholeBtn.TextSize = 14 Instance.new("UICorner", BlackholeBtn).CornerRadius = UDim.new(0, 6) PlaneBtn.Name = "PlaneBtn" PlaneBtn.Parent = MainFrame PlaneBtn.BackgroundColor3 = Color3.fromRGB(40, 40, 40) PlaneBtn.Position = UDim2.new(0.1, 0, 0.4, 0) PlaneBtn.Size = UDim2.new(0.8, 0, 0, 40) PlaneBtn.Font = Enum.Font.GothamSemibold PlaneBtn.Text = "Plane Attack: OFF" PlaneBtn.TextColor3 = Color3.fromRGB(255, 255, 255) PlaneBtn.TextSize = 14 Instance.new("UICorner", PlaneBtn).CornerRadius = UDim.new(0, 6) RadiusLabel.Name = "RadiusLabel" RadiusLabel.Parent = MainFrame RadiusLabel.BackgroundTransparency = 1 RadiusLabel.Position = UDim2.new(0.1, 0, 0.6, 0) RadiusLabel.Size = UDim2.new(0.4, 0, 0, 30) RadiusLabel.Font = Enum.Font.Gotham RadiusLabel.Text = "Radius:" RadiusLabel.TextColor3 = Color3.fromRGB(200, 200, 200) RadiusLabel.TextSize = 14 RadiusLabel.TextXAlignment = Enum.TextXAlignment.Left RadiusSlider.Name = "RadiusInput" RadiusSlider.Parent = MainFrame RadiusSlider.BackgroundColor3 = Color3.fromRGB(30, 30, 30) RadiusSlider.Position = UDim2.new(0.5, 0, 0.6, 0) RadiusSlider.Size = UDim2.new(0.4, 0, 0, 30) RadiusSlider.Font = Enum.Font.Gotham RadiusSlider.PlaceholderText = "15" RadiusSlider.Text = "15" RadiusSlider.TextColor3 = Color3.fromRGB(255, 255, 255) RadiusSlider.TextSize = 14 Instance.new("UICorner", RadiusSlider).CornerRadius = UDim.new(0, 4) StatusLabel.Name = "Status" StatusLabel.Parent = MainFrame StatusLabel.BackgroundTransparency = 1 StatusLabel.Position = UDim2.new(0, 0, 0.85, 0) StatusLabel.Size = UDim2.new(1, 0, 0, 30) StatusLabel.Font = Enum.Font.GothamItalic StatusLabel.Text = "Ready to Chaos вҡҷпёҸ" StatusLabel.TextColor3 = Color3.fromRGB(150, 150, 150) StatusLabel.TextSize = 12 local dragging, dragInput, dragStart, startPos local function update(input) local delta = input.Position - dragStart MainFrame.Position = UDim2.new(startPos.X.Scale, startPos.X.Offset + delta.X, startPos.Y.Scale, startPos.Y.Offset + delta.Y) end MainFrame.InputBegan:Connect(function(input) if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then dragging = true dragStart = input.Position startPos = MainFrame.Position input.Changed:Connect(function() if input.UserInputState == Enum.UserInputState.End then dragging = false end end) end end) MainFrame.InputChanged:Connect(function(input) if input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch then dragInput = input end end) UserInputService.InputChanged:Connect(function(input) if input == dragInput and dragging then update(input) end end) local humanoidRootPart, Attachment1 local function setupBlackhole() local character = LocalPlayer.Character or LocalPlayer.CharacterAdded:Wait() humanoidRootPart = character:WaitForChild("HumanoidRootPart") local Folder = Instance.new("Folder", Workspace) Folder.Name = "ManusExploitFolder" local Part = Instance.new("Part", Folder) Attachment1 = Instance.new("Attachment", Part) Part.Anchored = true Part.CanCollide = false Part.Transparency = 1 return humanoidRootPart, Attachment1 end humanoidRootPart, Attachment1 = setupBlackhole() spawn(function() while true do RunService.Heartbeat:Wait() settings().Physics.AllowSleep = false sethiddenproperty(LocalPlayer, "SimulationRadius", math.huge) sethiddenproperty(LocalPlayer, "MaxSimulationRadius", math.huge) end end) local function ForcePart(v) if v:IsA("BasePart") and not v.Anchored and not v.Parent:FindFirstChild("Humanoid") and v.Name ~= "Handle" then for _, x in next, v:GetChildren() do if x:IsA("BodyAngularVelocity") or x:IsA("BodyForce") or x:IsA("BodyGyro") or x:IsA("BodyPosition") or x:IsA("BodyThrust") or x:IsA("BodyVelocity") or x:IsA("RocketPropulsion") or x:IsA("AlignPosition") or x:IsA("Torque") then x:Destroy() end end v.CanCollide = false v.Velocity = Vector3.new(30, 30, 30) local Torque = Instance.new("Torque", v) Torque.Torque = Vector3.new(100000, 100000, 100000) local AlignPosition = Instance.new("AlignPosition", v) local Attachment2 = Instance.new("Attachment", v) Torque.Attachment0 = Attachment2 AlignPosition.MaxForce = math.huge AlignPosition.MaxVelocity = math.huge AlignPosition.Responsiveness = 200 AlignPosition.Attachment0 = Attachment2 AlignPosition.Attachment1 = Attachment1 end end local function toggleBlackHole() blackHoleActive = not blackHoleActive if blackHoleActive then BlackholeBtn.Text = "Blackhole: ON" BlackholeBtn.TextColor3 = Color3.fromRGB(0, 255, 0) StatusLabel.Text = "Sucking everything... рҹҢҖ" spawn(function() while blackHoleActive do RunService.RenderStepped:Wait() angle = angle + math.rad(angleSpeed) local offsetX = math.cos(angle) * radius local offsetZ = math.sin(angle) * radius Attachment1.WorldCFrame = humanoidRootPart.CFrame * CFrame.new(offsetX, 0, offsetZ) for _, v in next, Workspace:GetDescendants() do if v:IsA("BasePart") and not v:FindFirstChild("AlignPosition") then ForcePart(v) end end end end) else BlackholeBtn.Text = "Blackhole: OFF" BlackholeBtn.TextColor3 = Color3.fromRGB(255, 255, 255) StatusLabel.Text = "Blackhole stopped." Attachment1.WorldCFrame = CFrame.new(0, -1000, 0) for _, v in next, Workspace:GetDescendants() do if v:IsA("BasePart") then local ap = v:FindFirstChild("AlignPosition") if ap then ap:Destroy() end local tq = v:FindFirstChild("Torque") if tq then tq:Destroy() end end end end end local function getPlane() local p = Workspace:FindFirstChild("Plane") if p and p:FindFirstChild("Plane") then return p.Plane end return nil end local function togglePlaneAttack() planeAttackActive = not planeAttackActive if planeAttackActive then PlaneBtn.Text = "Plane Attack: ON" PlaneBtn.TextColor3 = Color3.fromRGB(255, 0, 0) StatusLabel.Text = "Click to strike! вңҲпёҸ" else PlaneBtn.Text = "Plane Attack: OFF" PlaneBtn.TextColor3 = Color3.fromRGB(255, 255, 255) StatusLabel.Text = "Plane Attack disabled." local plane = getPlane() if plane then if plane:FindFirstChild("PlaneBV") then plane.PlaneBV:Destroy() end if plane:FindFirstChild("PlaneAV") then plane.PlaneAV:Destroy() end end end end UserInputService.InputBegan:Connect(function(input, processed) if not processed and planeAttackActive and input.UserInputType == Enum.UserInputType.MouseButton1 then local plane = getPlane() if plane then local mouse = LocalPlayer:GetMouse() local target = mouse.Hit.p local bv = plane:FindFirstChild("PlaneBV") or Instance.new("BodyVelocity", plane) bv.Name = "PlaneBV" bv.MaxForce = Vector3.new(math.huge, math.huge, math.huge) local av = plane:FindFirstChild("PlaneAV") or Instance.new("BodyAngularVelocity", plane) av.Name = "PlaneAV" av.MaxTorque = Vector3.new(math.huge, math.huge, math.huge) av.AngularVelocity = Vector3.new(0, 50, 0) plane.CFrame = CFrame.new(plane.Position, target) bv.Velocity = (target - plane.Position).Unit * planeSpeed StatusLabel.Text = "Plane incoming! рҹ’Ҙ" else StatusLabel.Text = "Error: Plane not found! вқҢ" end end end) BlackholeBtn.MouseButton1Click:Connect(toggleBlackHole) PlaneBtn.MouseButton1Click:Connect(togglePlaneAttack) RadiusSlider.FocusLost:Connect(function() local val = tonumber(RadiusSlider.Text) if val then radius = val StatusLabel.Text = "Radius set to: " .. val else RadiusSlider.Text = tostring(radius) end end) LocalPlayer.CharacterAdded:Connect(function() humanoidRootPart, Attachment1 = setupBlackhole() if blackHoleActive then blackHoleActive = false toggleBlackHole() end end) StatusLabel.Text = "Manus Exploit Loaded! рҹҳҲ" print("Manus Exploit Loaded Successfully.")















































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































